class Solution {
public:
    double new21Game(int n, int k, int maxPts) {
        if (k == 0 || n >= k + maxPts) return 1.0;
        vector<double> dp(n + 1, 0.0);
        double p = 0.0, sum = 1.0;
        dp[0] = 1.0;
        for (int i = 1; i <= n; ++i) {
            dp[i] = sum / maxPts;
            if (i < k) sum += dp[i];
            if (i >= maxPts) sum -= dp[i - maxPts];
        }
        double ans = 0.0;
        for (int i = k; i <= n; ++i) ans += dp[i];
        return ans;
    }
};
